function promiseAllStepN(n, list) {
  const inputList = [...list]; // jangan mutasi array asli
  const head = inputList.slice(0, n);
  const tail = inputList.slice(n);
  const resolved = [];
  let processed = 0;

  return new Promise((resolve) => {
    if (head.length === 0) {
      resolve([]);
      return;
    }

    head.forEach((x) => {
      const res = x();
      resolved.push(res);
      res.then(() => runNext());
    });

    function runNext() {
      if (processed === tail.length) {
        resolve(Promise.all(resolved));
      } else {
        const next = tail[processed]();
        resolved.push(next.then((x) => { runNext(); return x; }));
        processed++;
      }
    }
  });
}

module.exports = (n) => (list) => promiseAllStepN(n, list);
